1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_DISCOUNT = 15;
3	const BLOCK_SIZE = 3;
4	const FIRST_INSURANCE_RATE = 0.1;
5	const LOYALTY_DISCOUNT_RATE = 0.2;
6	const LOYALTY_YEARS_THRESHOLD = 2;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const CURSED_RATE = 0.5;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	const ITEM_BASE_PRICES: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	type Item = { type: string; enchantment?: number; cursed?: boolean; material?: string };
24	type Customer = { yearsWithMHPCO?: number };
25	type QuoteStep = { op: "quote"; items: Item[] };
26	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: { itemType: string; amount: number }[] } };
27	type Step = QuoteStep | ClaimStep;
28	type Scenario = {
29	  customer?: Customer;
30	  steps: Step[];
31	};
32	
33	function countItemsByType(items: Item[]): Map<string, number> {
34	  const counts = new Map<string, number>();
35	  for (const item of items) {
36	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
37	  }
38	  return counts;
39	}
40	
41	function blockDiscountFor(type: string, count: number): number {
42	  const isComponent = COMPONENT_TYPES.has(type);
43	  const formsBlock = count === BLOCK_SIZE;
44	  return isComponent && formsBlock ? BLOCK_OF_THREE_DISCOUNT : 0;
45	}
46	
47	function basePremiumForGroup(type: string, count: number): number {
48	  return count * ITEM_BASE_PRICES[type] - blockDiscountFor(type, count);
49	}
50	
51	function computePolicyBase(items: Item[]): number {
52	  const itemCountsByType = countItemsByType(items);
53	  let basePremium = 0;
54	  for (const [type, count] of itemCountsByType.entries()) {
55	    basePremium += basePremiumForGroup(type, count);
56	  }
57	  return basePremium;
58	}
59	
60	function sumItemSurcharge(
61	  items: Item[],
62	  rate: number,
63	  applies: (item: Item) => boolean,
64	): number {
65	  return items
66	    .filter(applies)
67	    .reduce((sum, item) => sum + ITEM_BASE_PRICES[item.type] * rate, 0);
68	}
69	
70	function computeFirstInsuranceSurcharge(policyBase: number): number {
71	  return policyBase * FIRST_INSURANCE_RATE;
72	}
73	
74	function computeHighEnchantmentSurcharge(items: Item[]): number {
75	  return sumItemSurcharge(
76	    items,
77	    HIGH_ENCHANTMENT_RATE,
78	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
79	  );
80	}
81	
82	function computeCursedSurcharge(items: Item[]): number {
83	  return sumItemSurcharge(items, CURSED_RATE, (item) => item.cursed === true);
84	}
85	
86	function computeLoyaltyDiscount(policyBase: number, customer: Customer): number {
87	  const years = customer.yearsWithMHPCO ?? 0;
88	  if (years >= LOYALTY_YEARS_THRESHOLD) {
89	    return policyBase * LOYALTY_DISCOUNT_RATE;
90	  }
91	  return 0;
92	}
93	
94	function computeFollowUpDiscount(policyBase: number, isFollowUpQuote: boolean): number {
95	  return isFollowUpQuote ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
96	}
97	
98	function computeQuotePremium(
99	  items: Item[],
100	  customer: Customer,
101	  isFollowUpQuote: boolean,
102	): number {
103	  const policyBase = computePolicyBase(items);
104	  const premium =
105	    policyBase +
106	    computeHighEnchantmentSurcharge(items) +
107	    computeCursedSurcharge(items) +
108	    computeFirstInsuranceSurcharge(policyBase) -
109	    computeLoyaltyDiscount(policyBase, customer) -
110	    computeFollowUpDiscount(policyBase, isFollowUpQuote) +
111	    PROCESSING_FEE;
112	  return Math.ceil(premium);
113	}
114	
115	export function runScenario(scenario: unknown): unknown {
116	  const s = scenario as Scenario;
117	  const customer = s.customer ?? { yearsWithMHPCO: 0 };
118	
119	  const results = s.steps.map((step, index) => {
120	    if (step.op === "quote") {
121	      return { premium: computeQuotePremium(step.items, customer, index > 0) };
122	    }
123	    const quote = s.steps[step.policy] as QuoteStep;
124	    let payout = 0;
125	    for (const damage of step.incident.damages) {
126	      const item = quote.items.find((i) => i.type === damage.itemType)!;
127	      const halfRule = (item.enchantment ?? 0) >= 8;
128	      const reimbursement = halfRule ? damage.amount * 0.5 : damage.amount;
129	      payout += reimbursement - 100;
130	    }
131	    return { payout: Math.floor(payout) };
132	  });
133	  return { results };
134	}
