const CURSED_RATE = 0.5;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;
const CLAIM_DEDUCTIBLE = 100;
const HALF_PAYMENT_ENCHANTMENT_THRESHOLD = 8;
const HALF_PAYMENT_RATE = 0.5;

